import json
from pathlib import Path

import pytest

AC_UID = "efbe5ef12975e7e7"
AC_TYPE = "data"

REPO_ROOT = Path(__file__).resolve().parents[3]
TOOL_POLICY = REPO_ROOT / "policies" / "tool-policy.v1.json"


def test_AC_01():
    """
    GIVEN: policies/tool-policy.v1.json is parsed as JSON
    WHEN:  the keys of .roles are enumerated
    THEN:  key 'test-writer' MUST exist with allowed_tools containing the full 8-tool list [Read, Glob, Grep, Bash, Write, Edit, MultiEdit, Skill] (Write/Edit/MultiEdit required for test-writer to actually write test files); denied_write_path_prefixes mirroring other non-core specialists; rationale non-empty
    """
    assert TOOL_POLICY.is_file(), f"policies/tool-policy.v1.json not found at {TOOL_POLICY}"
    data = json.loads(TOOL_POLICY.read_text(encoding="utf-8"))
    roles = data.get("roles", {})
    assert "test-writer" in roles, (
        f"role 'test-writer' missing from policies/tool-policy.v1.json .roles "
        f"(have: {sorted(roles.keys())})"
    )
    tw = roles["test-writer"]
    for key in ("allowed_tools", "allowed_write_path_prefixes", "denied_write_path_prefixes", "rationale"):
        assert key in tw, f"test-writer role missing key '{key}' in tool-policy.v1.json"
    required_tools = {"Read", "Glob", "Grep", "Bash", "Write", "Edit", "MultiEdit", "Skill"}
    missing_tools = required_tools - set(tw["allowed_tools"])
    assert not missing_tools, (
        f"test-writer allowed_tools missing: {sorted(missing_tools)} (have: {tw['allowed_tools']})"
    )
    required_denied = {
        "/src/", "/app/", "/lib/",
        "/.claude/hooks/", "/.claude/agents/", "/.claude/commands/",
        "/.claude/policies/", "/.claude/schemas/", "/.claude/scripts/",
        "/.claude/settings.json",
    }
    missing_denied = required_denied - set(tw["denied_write_path_prefixes"])
    assert not missing_denied, (
        f"test-writer denied_write_path_prefixes missing: {sorted(missing_denied)}"
    )
    assert isinstance(tw["rationale"], str) and tw["rationale"].strip(), (
        "test-writer rationale must be non-empty string"
    )
